function solve(nums, k) {
    let totalSum = 0;
    let modCount = 0;
    let modMap = new Map();

    modMap.set(0, 1); // Base case: sum 0 mod k is 0

    for (let num of nums) {
        totalSum += num;
        let mod = totalSum % k;
        modCount += mod;

        if (modMap.has(mod)) {
            modMap.set(mod, modMap.get(mod) + 1);
        } else {
            modMap.set(mod, 1);
        }
    }

    // The minimum possible sum is the total sum minus k multiplied by the number of times we can remove a subarray with sum divisible by k
    return totalSum - (modCount / k) * k;
}

